import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';

const client = new BedrockAgentRuntimeClient({ region: 'us-east-1' });

interface SessionState {
  previousContext?: string;
  turnCount: number;
}

function detectSessionLoss(response: InvokeAgentCommandOutput, expectedState: SessionState): string[] {
  const issues: string[] = [];
  const sessionState = response.completion?.sessionState?.sessionAttributes;

  if (expectedState.previousContext && !sessionState?.includes(expectedState.previousContext)) {
    issues.push('Session context lost between turns');
  }

  return issues;
}

